using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "it", "its",
        "this", "that", "these", "those", "he", "she", "they", "we", "you",
        "i", "me", "him", "her", "us", "them", "my", "your", "his", "our",
        "their", "what", "which", "who", "whom", "will", "would", "could",
        "should", "may", "might", "can", "do", "does", "did", "has", "have",
        "had", "be", "been", "being", "not", "no", "nor", "so", "if", "then",
        "than", "too", "very", "just", "about", "above", "also", "each",
        "how", "all", "both", "each", "other", "such", "only", "own", "same"
    };

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency.
    /// </summary>
    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scoredSentences = sentences
            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        return string.Join(" ", scoredSentences);
    }

    public int CountSentences(string text) => SplitIntoSentences(text).Count;

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary().Matches(text)
            .Select(m => m.Value.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    frequencies.TryGetValue(word, out int count);
                    frequencies[word] = count + 1;
                }
            }
        }

        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = ExtractWords(sentence);
        if (words.Count == 0) return 0;

        double score = 0;
        foreach (var word in words)
        {
            if (wordFrequencies.TryGetValue(word, out int freq))
                score += freq;
        }

        return score / words.Count;
    }

    private static List<string> ExtractWords(string text)
    {
        return WordPattern().Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .ToList();
    }

    [GeneratedRegex(@"[^.!?]*[.!?]+|[^.!?]+$", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizer;

    public SummarizeController(DocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest(new { error = "DocumentText must not be empty." });

        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);
        var originalCount = _summarizer.CountSentences(request.DocumentText);
        var summaryCount = _summarizer.CountSentences(summary);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

